class Solution:
    def diffWaysToCompute(self, expression):
        # Brute force: same divide-and-conquer without memoization.
        if expression.lstrip('-').isdigit():
            return [int(expression)]
        results = []
        for i, ch in enumerate(expression):
            if ch in '+-*':
                for l in self.diffWaysToCompute(expression[:i]):
                    for r in self.diffWaysToCompute(expression[i+1:]):
                        if ch == '+': results.append(l + r)
                        elif ch == '-': results.append(l - r)
                        else: results.append(l * r)
        return results

