class Solution:
    def diffWaysToCompute(self, expression):
        memo = {}
        def dp(s):
            if s in memo:
                return memo[s]
            if s.lstrip('-').isdigit():
                return [int(s)]
            res = []
            for i, ch in enumerate(s):
                if ch in '+-*':
                    for l in dp(s[:i]):
                        for r in dp(s[i+1:]):
                            if ch == '+': res.append(l + r)
                            elif ch == '-': res.append(l - r)
                            else: res.append(l * r)
            memo[s] = res
            return res
        return dp(expression)

