var diffWaysToCompute = function(expression) {
    const memo = new Map();
    function dp(s) {
        if (memo.has(s)) return memo.get(s);
        if (/^-?\d+$/.test(s)) return [parseInt(s)];
        const res = [];
        for (let i = 0; i < s.length; i++) {
            const ch = s[i];
            if (ch === '+' || ch === '-' || ch === '*') {
                for (const l of dp(s.slice(0, i))) {
                    for (const r of dp(s.slice(i + 1))) {
                        if (ch === '+') res.push(l + r);
                        else if (ch === '-') res.push(l - r);
                        else res.push(l * r);
                    }
                }
            }
        }
        memo.set(s, res);
        return res;
    }
    return dp(expression);
};
